B.amD=new A.ha("Son g\xfcncelleme: 18 Mart 2026",null)
B.an6=new A.hw("Hizmet Tan\u0131m\u0131",null)
B.amw=new A.ha("Koala, yapay zeka destekli bir mekan analiz uygulamas\u0131d\u0131r. Kullan\u0131c\u0131lar soru foto\u011fraf\u0131 \xe7ekerek ad\u0131m ad\u0131m \xe7\xf6z\xfcm alabilir. Uygulama 9 farkl\u0131 bran\u015fta AI destekli \xf6\u011fretim hizmeti sunar.",null)
B.an2=new A.hw("Hesap ve Kay\u0131t",null)
B.akG=new A.dJ("Uygulamay\u0131 kullanmak i\xe7in Google veya telefon numaras\u0131 ile hesap olu\u015fturman\u0131z gerekir",null)
