B.anb=new A.hw("Kredi Sistemi",null)
B.akq=new A.dJ("Her yeni kullan\u0131c\u0131ya 10 \xfccretsiz kredi verilir",null)
B.akP=new A.dJ("Her mekan analizi 1 kredi harcar",null)
B.akO=new A.dJ("Ek kredi uygulama i\xe7i sat\u0131n alma ile edinilebilir",null)
B.akN=new A.dJ("Sat\u0131n al\u0131nan krediler iade edilemez",null)
B.an3=new A.hw("Kabul Edilebilir Kullan\u0131m",null)
B.amt=new A.ha("Uygulamay\u0131 yaln\u0131zca ki\u015fisel mekan analizi ama\xe7l\u0131 kullanabilirsiniz. A\u015fa\u011f\u0131daki davran\u0131\u015flar yasakt\u0131r:",null)
B.akM=new A.dJ("Uygulamay\u0131 k\xf6t\xfcye kullanmak veya ba\u015fkalar\u0131n\u0131n kullan\u0131m\u0131n\u0131 engellemek",null)
B.akF=new A.dJ("Otomatik botlar veya scraper kullanmak",null)
B.akI=new A.dJ("Uygulamay\u0131 s\u0131nav s\u0131ras\u0131nda kopya \xe7ekmek i\xe7in kullanmak",null)
